- [ ] **Step 1: Create the draggable list**

Create `apps/web/app/[locale]/(demos)/completion/draggable-list.tsx`:

```tsx
"use client";

import {
  closestCenter,
  DndContext,
  type DragEndEvent,
  KeyboardSensor,
  PointerSensor,
  useSensor,
  useSensors,
} from "@dnd-kit/core";
import {
  arrayMove,
  SortableContext,
  sortableKeyboardCoordinates,
  useSortable,
  verticalListSortingStrategy,
} from "@dnd-kit/sortable";
import { CSS } from "@dnd-kit/utilities";
import { Button } from "@repo/design-system/components/ui/button";
import { cn } from "@repo/design-system/lib/utils";
import { useEffect, useRef, useState } from "react";
import { patchOrder } from "./fake-server";
import { type Item, INITIAL_ITEMS } from "./items";
import { buggyReorder } from "./stale-closure";

interface DraggableListProps {
  remountKey: number;
  onDragPerformed: () => void;
  onItemVanished: () => void;
  onResetRequested: () => void;
  onRefreshRequested: () => void;
}

function SortableRow({ item }: { item: Item }) {
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } =
    useSortable({ id: item.id });

  const style: React.CSSProperties = {
    transform: CSS.Transform.toString(transform),
    transition,
  };

  return (
    <li
      ref={setNodeRef}
      style={style}
      {...attributes}
      {...listeners}
      className={cn(
        "flex cursor-grab select-none items-center gap-3 rounded-md border border-border/60 bg-background/60 px-4 py-3 text-foreground/85 active:cursor-grabbing",
        isDragging && "shadow-md ring-1 ring-foreground/10"
      )}
    >
      <span
        aria-hidden="true"
        className="font-mono text-foreground/35 text-xs tracking-[0.2em]"
      >
        ⋮⋮
      </span>
      <span>{item.label}</span>
    </li>
  );
}

export function DraggableList({
  remountKey,
  onDragPerformed,
  onItemVanished,
  onResetRequested,
  onRefreshRequested,
}: DraggableListProps) {
  const [items, setItems] = useState<readonly Item[]>(INITIAL_ITEMS);
  // The deliberate stale snapshot — captured at render, not at update.
  const staleRef = useRef<readonly Item[]>(items);
  // Refresh remounts effectively reset to INITIAL_ITEMS via the key prop on
  // the parent — so we don't need to reload from fake-server here. The fake
  // server's read returning INITIAL_ITEMS is the demonstrable failure (the
  // PATCH writes never landed at the read key).
  useEffect(() => {
    staleRef.current = items;
    // We deliberately do NOT update the ref on every state change — only on
    // commit. That is what makes the snapshot stale during a fast double-drag.
  });

  const sensors = useSensors(
    useSensor(PointerSensor, {
      activationConstraint: { distance: 4 },
    }),
    useSensor(KeyboardSensor, {
      coordinateGetter: sortableKeyboardCoordinates,
    })
  );

  function handleDragEnd(event: DragEndEvent) {
    const { active, over } = event;
    if (!over || active.id === over.id) return;

    const fromId = String(active.id);
    const toId = String(over.id);
    const previousLength = items.length;

    // The buggy reorder uses the stale snapshot if it diverges from current.
    const next = buggyReorder({
      fromId,
      toId,
      current: items,
      stale: staleRef.current,
    });
    setItems(next);

    onDragPerformed();
    if (next.length < previousLength) {
      onItemVanished();
    }

    // Fire the (lying) PATCH. We don't await — render shouldn't block on it.
    void patchOrder(next);
  }

  function handleSafeReorder(fromId: string, toId: string) {
    // Used by the keyboard fallback for screen-reader determinism — same path.
    const next = buggyReorder({
      fromId,
      toId,
      current: items,
      stale: staleRef.current,
    });
    setItems(next);
  }

  // remountKey changes → component is remounted by the parent via key.
  // Items reset to INITIAL_ITEMS automatically (the useState initializer runs).
  // We don't need to consume remountKey directly here.
  void remountKey;
  void handleSafeReorder;

  function handleResetClick() {
    setItems(INITIAL_ITEMS);
    onResetRequested();
  }

  return (
    <div className="rounded-2xl border border-border bg-card/40 p-5 shadow-sm sm:p-6">
      <DndContext
        sensors={sensors}
        collisionDetection={closestCenter}
        onDragEnd={handleDragEnd}
      >
        <SortableContext
          items={items.map((item) => item.id)}
          strategy={verticalListSortingStrategy}
        >
          <ul className="flex flex-col gap-2">
            {items.map((item) => (
              <SortableRow item={item} key={item.id} />
            ))}
          </ul>
        </SortableContext>
      </DndContext>
      <div className="mt-5 flex items-center justify-end gap-2">
        <Button
          aria-label="Reset list to original six items"
          onClick={handleResetClick}
          size="sm"
          variant="ghost"
        >
          Reset list
        </Button>
        <Button
          aria-label="Refresh demo — re-mount the list to test persistence"
          onClick={onRefreshRequested}
          size="sm"
          variant="outline"
        >
          Refresh demo
        </Button>
      </div>
    </div>
  );
}

// arrayMove is imported from @dnd-kit/sortable but we use buggyReorder
// instead. Kept reachable so future safe-mode tweaks have it on hand.
void arrayMove;
```

Notes on mechanism:
- The `staleRef` is updated inside `useEffect` (commit phase). On a fast double-drag, the second `handleDragEnd` runs before the effect commits, so `staleRef.current` is the *previous* commit's items list. `buggyReorder` then sees `current !== stale` and triggers the deterministic drop.
- `void arrayMove`, `void handleSafeReorder`, `void remountKey` keep imports/locals reachable for future iteration; Biome (ultracite) is fine with them but they could be removed by the reviewer if preferred.
- Keyboard reorder via dnd-kit's `KeyboardSensor` runs the same `handleDragEnd` path, so the C breakage is reproducible by keyboard too.

